(window.webpackJsonp=window.webpackJsonp||[]).push([[316],{943:function(e,n){e.exports='\x3c!-- \ntitle: 02-React入门\nsort: \n--\x3e \n\n## 第一个程序\n\n1. 基础语法\n\n```react\n// 渲染Dom\nReactDOM.render(React Element, Element)\n// 创建元素\nReact.createElement(label, attr, content)\n// 继承组件\nReact.Component\n```\n\n2. HelloWorld\n\n```html\n<html lang="en">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>Demo1</title>\n    \x3c!-- CDN 组件 --\x3e\n    <script crossorigin src="https://unpkg.com/react@17/umd/react.development.js"><\/script>\n    <script crossorigin src="https://unpkg.com/react-dom@17/umd/react-dom.development.js"><\/script>\n</head>\n\n<body>\n    <div id="app"></div>\n    <script>\n        var hello = React.createElement(\'h1\',{},"HelloWorld");\n        ReactDOM.render(hello,document.getElementById(\'app\'));\n    <\/script>\n</body>\n\n</html>\n```\n\n> 运行不成功尝试`yarn add react react-dom --save`\n\n```html\n<html lang="en">\n\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>Demo1</title>\n    \x3c!-- <script crossorigin src="https://unpkg.com/react@17/umd/react.development.js"><\/script> --\x3e\n    \x3c!-- <script crossorigin src="https://unpkg.com/react-dom@17/umd/react-dom.development.js"><\/script> --\x3e\n    <script src="node_modules\\react\\umd\\react.development.js"><\/script>\n    <script src="node_modules\\react-dom\\umd\\react-dom.development.js"><\/script>\n    <script src="https://unpkg.com/babel-standalone@6.26.0/babel.min.js"><\/script>\n</head>\n\n<body>\n    <div id="app"></div>\n    <script type="text/babel">\n        // var hello = React.createElement(\'h1\',{},"HelloWorld");\n        // babel6 语法糖\n        ReactDOM.render(\n        \t<h1>HelloWorld</h1>\n        \t,document.getElementById(\'app\'));\n    <\/script>\n</body>\n\n</html>\n```\n\n## 语法糖\n\n> babel6\n>\n> 属性要换成驼峰命名\n\n```react\nvar hello = React.createElement(\'h1\', {\n    className: \'red\',\n    name: \'jack\'\n}, "HelloWorld");\nReactDOM.render(hello, document.getElementById(\'app\'));\n\n// 替代品\nReactDOM.render(\n    <h1 className="res" name="fzf">HelloWorld</h1>\n    , document.getElementById(\'app\'));\n\n// 新写法\n<script type="text/babel">\n    var name = \'fzf\';\n    var ele = <h1 className="red">Hello, {name}</h1>;\n    ReactDOM.render(\n    ele\n    , document.getElementById(\'app\'));\n<\/script>\n```\n\n### 动态渲染\n\n> 动态渲染，无需刷新\n\n```react\nfunction tick() {\n    var time = new Date().toLocaleTimeString();\n    var ele = <div>\n        <h1 className="red" name="fzf">Hello, fzf</h1>\n        <h2>{time}</h2>\n    </div>;\n    ReactDOM.render(\n        ele\n        , document.getElementById(\'app\'));\n}\nsetInterval(tick, 1000);\n```\n'}}]);